const r=e=>{if(!e)return"N/A";const t=new Date(e);return isNaN(t.getTime())?"N/A":t.toLocaleDateString("en-US",{month:"short",day:"numeric",year:"numeric"})},n=e=>{if(!e)return"N/A";const t=new Date(e);return isNaN(t.getTime())?"N/A":t.toLocaleTimeString("en-US",{hour:"2-digit",minute:"2-digit"})},i=e=>{if(!e)return"N/A";const t=new Date(e);return isNaN(t.getTime())?"N/A":`${r(e)} at ${n(e)}`};export{i as a,r as f};
